import{_ as r,C as o,o as a,c as d,a7 as i,E as n}from"./chunks/framework.D3qk93i9.js";const w=JSON.parse('{"title":"Firmware Updater","description":"Update OSRBOT firmware in the browser with app OTA or BOOT recovery flashing.","frontmatter":{"title":"Firmware Updater","description":"Update OSRBOT firmware in the browser with app OTA or BOOT recovery flashing."},"headers":[],"relativePath":"en/updater.md","filePath":"en/updater.md","lastUpdated":1781678114000}'),s={name:"en/updater.md"};function c(l,e,p,m,h,f){const t=o("FirmwareUpdater");return a(),d("div",null,[e[0]||(e[0]=i('<h1 id="firmware-updater" tabindex="-1">Firmware Updater <a class="header-anchor" href="#firmware-updater" aria-label="Permalink to &quot;Firmware Updater&quot;">​</a></h1><blockquote><p>Chrome or Edge is required because this page uses the Web Serial API.</p></blockquote><p>This page provides two update paths:</p><ul><li><strong>App update</strong>: the device boots normally and only the app partition is updated. BOOT mode is not required.</li><li><strong>Recovery flash</strong>: first flash, factory restore, or broken firmware recovery. BOOT download mode is required and a full flash image is written.</li></ul><p>Remote firmware URL accepts two formats:</p><ul><li>Site-relative path, for example <code>/firmware/osrbot_ESP32S3_IDF_App.bin</code></li><li>Full HTTPS URL, for example <code>https://example.com/firmware.bin</code></li></ul><p>Recommended factory test after flashing the diagnostic firmware:</p><ol><li>Open the serial monitor, send <code>diag</code>, and check SN, flash, heap, I2C, IMU, magnetometer, and SBUS status.</li><li>Send <code>imu</code> and <code>mag</code>, then gently rotate the board and confirm raw data changes.</li><li>Send <code>ledtest</code> and <code>beeptest</code> to verify the LED and buzzer.</li><li>Send <code>rc</code>, move the transmitter sticks, and confirm channel values change.</li><li>Lift the vehicle, then send <code>servo left</code>, <code>servo center</code>, and <code>servo right</code>.</li><li>Lift the vehicle, then send <code>motor fwd</code>, <code>motor rev</code>, and <code>motor stop</code>.</li><li>Lift the vehicle, send <code>drive on</code>, use CH0/CH2 for limited low-speed RC testing, then send <code>drive off</code>.</li></ol>',8)),n(t,{locale:"en"})])}const _=r(s,[["render",c]]);export{w as __pageData,_ as default};
